<script setup lang="ts">import {currentLanguage} from "../../services/LanguageService.ts";import TitleBar from "../../components/TitleBar.vue";import ThemeEditor from "./components/ThemeEditor.vue";import ThemePreview from "./components/ThemePreview.vue";import {getCustomTheme, saveCustomTheme} from "../../store/CustomThemeConfig.ts";import {applyPreviewThemeToDOM, forbidCalculate, themeConfig} from "./composables/ThemeEditorDataComposable.ts";import {useMessage} from "naive-ui";import {computed, onMounted, ref, watch} from "vue";import {themes} from "../../services/ThemeService.ts";import {open, save} from "@tauri-apps/plugin-dialog";import {readTextFile, writeTextFile} from "@tauri-apps/plugin-fs";import {invoke} from "@tauri-apps/api/core";import {emit} from "@tauri-apps/api/event";const message = useMessage();// 预设主题选择const selectBasicTheme = ref('');const themeOptions = themes.value.filter(t => t.id !== 'custom').map(t => {  return {value: t.id, label: currentLanguage.value.pages.list.menu[t.id]}});const showThemeText = computed(() => {  return currentLanguage.value.pages.list.menu[selectBasicTheme.value] || currentLanguage.value.pages.settings.themeEditor.selectTheme;})// 主题导出完成const exportSuccessModalVisible = ref(false);const exportFilePath = ref('');/** * 导入主题 */async function onImport(): Promise<void> {  const filePath = await open({    multiple: false,    directory: false,    title: currentLanguage.value.pages.settings.themeEditor.themeImport,    filters: [{      name: currentLanguage.value.pages.settings.themeEditor.themeFile,      extensions: ['epth']    }]  });  if (!filePath) {    return;  }  const msg = message.loading(currentLanguage.value.pages.settings.themeEditor.loadingThemeFileMsg, {    duration: 0  })  try {    const data = await readTextFile(filePath);    Object.assign(themeConfig, JSON.parse(data));  } catch (e) {    message.error(currentLanguage.value.pages.settings.themeEditor.loadingThemeFileErrorMsg);  } finally {    msg.destroy();  }}/** * 导出主题 */async function onExport(): Promise<void> {  const filePath = await save({    defaultPath: 'customTheme',    title: currentLanguage.value.pages.settings.themeEditor.themeExport,    filters: [{      name: currentLanguage.value.pages.settings.themeEditor.themeFile,      extensions: ['epth']    }],    canCreateDirectories: true  })  if (!filePath) {    return;  }  const msg = message.loading(currentLanguage.value.pages.settings.themeEditor.exportingThemeFileMsg, {    duration: 0  })  await writeTextFile(filePath, JSON.stringify(themeConfig));  msg.destroy();  exportSuccessModalVisible.value = true;  exportFilePath.value = filePath;}/** * 显示文件所在位置 */async function onShowFile(): Promise<void> {  exportSuccessModalVisible.value = false;  await invoke('open_folder', {path: exportFilePath.value})}/** * 重置主题 */async function onReset(): Promise<void> {  forbidCalculate.value = true;  selectBasicTheme.value = '';  const oldTheme = await getCustomTheme();  Object.assign(themeConfig, oldTheme.colors);  applyPreviewThemeToDOM(themeConfig);  message.success(currentLanguage.value.pages.settings.themeEditor.resetFinishMsg);}/** * 保存主题 */async function saveTheme(): Promise<void> {  await saveCustomTheme(themeConfig);  await emit("reload-custom-theme");  message.success('保存成功')}watch(selectBasicTheme, (themeId) => {  const theme = themes.value.find(t => t.id === themeId);  if (theme) {    forbidCalculate.value = true;    Object.assign(themeConfig, JSON.parse(JSON.stringify(theme.colors)));    applyPreviewThemeToDOM(themeConfig);  }})onMounted(async () => {  // 初始化自定义主题  const theme = await getCustomTheme();  forbidCalculate.value = true;  Object.assign(themeConfig, theme.colors);})</script><template>  <titleBar      :title="currentLanguage.pages.settings.themeEditor.title"      :showCloseBtn="true"      :dev-tool="`theme-editor`"  />  <!-- 按钮行 -->  <div class="editor-content">    <div class="operation-line">      <n-popselect v-model:value="selectBasicTheme" :options="themeOptions" trigger="click">        <n-button>{{ showThemeText }}</n-button>      </n-popselect>      <n-button @click="onImport">{{ currentLanguage.pages.settings.themeEditor.importBtn }}</n-button>      <n-button @click="onExport">{{ currentLanguage.pages.settings.themeEditor.exportBtn }}</n-button>      <n-button @click="onReset">{{ currentLanguage.pages.settings.themeEditor.resetBtn }}</n-button>      <n-button type="primary" @click="saveTheme">{{ currentLanguage.pages.settings.themeEditor.saveBtn }}</n-button>    </div>    <!-- 主题编辑/预览 -->    <n-split direction="horizontal" style="height: 100%" :max="0.65" :min="0.35">      <template #1>        <!-- 颜色设置区域 -->        <theme-editor/>      </template>      <template #2>        <!-- 颜色预览区域 -->        <theme-preview/>      </template>    </n-split>    <!-- 主题导出完成确认框 -->    <n-modal v-model:show="exportSuccessModalVisible" title="主题导出完成" preset="dialog" :closable="false">      <span>{{ currentLanguage.pages.settings.themeEditor.exportedThemeFileModeContent }}{{ exportFilePath }}</span>      <template #action>        <n-button @click="onShowFile">{{ currentLanguage.pages.settings.themeEditor.openInFolderBtn }}</n-button>        <n-button type="primary" @click="exportSuccessModalVisible = false">          {{ currentLanguage.pages.settings.themeEditor.closeBtn }}        </n-button>      </template>    </n-modal>  </div></template><style scoped>.editor-content {  width: 100%;  height: calc(100vh - 25px);  display: flex;  flex-direction: column;}.operation-line {  display: flex;  justify-content: flex-end;  gap: 5px;  border-bottom: 1px solid var(--theme-universal-border);  padding: 5px 10px;}</style>